你们可以尝试一下这段代码，如果除了最终的结果数量以外，还有其它信息被打出，那可能就是发生了意料外的错误，如网络错误等。同时，还建议检查一下api登录时使用的账号设置，是否有正确设置“限制浏览的作品 (R-18)”。

```python
from pixivpy3 import AppPixivAPI

username = 'username'
password = 'password'

user_id = 13992671


def get_imageUrls(aapi, pid, illust_type='illust'):
    json_result = aapi.user_illusts(pid, type=illust_type)
    while 1:
        try:
            nLen = len(json_result.illusts)
        except Exception as e:
            print(e)

        for illust in json_result.illusts:
            yield illust

            if illust.page_count == 1 and illust.type != 'ugoira':
                # print(illust.meta_single_page.original_image_url)
                pass
            elif illust.page_count > 1:
                image_urls = [
                    page.image_urls.original
                    for page in illust.meta_pages
                ]
                # print(image_urls)
            else:
                image_urls = []

        try:
            next_qs = aapi.parse_qs(json_result.next_url)
            if next_qs is None:
                break
            json_result = aapi.user_illusts(**next_qs)
        except Exception as e:
            print(e)
            break

    return 1


def main():
    aapi = AppPixivAPI()
    aapi.login(username, password)

    illust_ids = set()
    for illust in get_imageUrls(aapi, user_id, 'illust'):
        illust_ids.add(illust.id)
    for illust in get_imageUrls(aapi, user_id, 'manga'):
        illust_ids.add(illust.id)

    print(len(illust_ids))


if __name__ == '__main__':
    main()
```

