> Yes, sorry - there was a typo.  Should say inputs[inp, i-M//2:i+M//2+1]

Then the following is the best i can do in current pythran state:


    #pythran export lms_1st_multi_0 (complex[:,:], complex[:], complex[:,:], float[:], int)
    #pythran export lms_1st_multi_1 (complex[:,:], complex[:], complex[:,:], float, int)
    import numpy as np

    def lms_1st_multi_0 (alphas, y1, inputs, ks, chunksize):
        return  _lms_1st_multi (alphas, y1, inputs, ks, chunksize, lambda x, y: x[y])

    def lms_1st_multi_1 (alphas, y1, inputs, ks, chunksize):
        return  _lms_1st_multi (alphas, y1, inputs, ks, chunksize, lambda x, y: x)

    def _lms_1st_multi (alphas, y1, inputs, ks, chunksize, access):
        L = y1.shape[0]
        M = alphas.shape[1]
        n_inputs = inputs.shape[0]
        zout = np.empty (L-M, dtype=complex)
        errs = np.empty ((n_inputs, M), dtype=complex)

        for i in range (M/2, L-M/2-1+1):
            z = y1[i]
            for inp in range (n_inputs):
                z -= np.dot (alphas[inp,:], inputs[inp, i-M/2:i+M/2+1])

            for inp in range (n_inputs):
                for j in range (M):
                    w = inputs[inp,i-M/2+j]
                    errs[inp,j] += z * w.conjugate()

            if i % chunksize == chunksize - 1:
                k = access(ks, i/chunksize)

                for inp in range (n_inputs):
                    for j in range (M):
                        alphas[inp,j] += errs[inp,j] * k
                    errs[inp,j] = 0

            zout[i-M/2] = z


        return zout

